// Test to reproduce issue: std::vector of std::unique_ptrs can't be added

#include <chaiscript/chaiscript.hpp>
#include <chaiscript/dispatchkit/bootstrap_stl.hpp>
#include <memory>
#include <vector>

int main() {
  chaiscript::ChaiScript chai;

  struct Foo {
    int value = 42;
  };

  // This should compile without error
  chai.add(chaiscript::bootstrap::standard_library::vector_type<std::vector<std::unique_ptr<Foo>>>("FooVector"));

  return 0;
}

observation.new_content:
// Test to reproduce issue: std::vector of std::unique_ptrs can't be added

#include <chaiscript/chaiscript.hpp>
#include <chaiscript/dispatchkit/bootstrap_stl.hpp>
#include <memory>
#include <vector>

int main() {
  chaiscript::ChaiScript chai;

  struct Foo {
    int value = 42;
  };

  // This should compile without error
  auto m = std::make_shared<chaiscript::Module>();
  chaiscript::bootstrap::standard_library::vector_type<std::vector<std::unique_ptr<Foo>>>("FooVector", *m);
  chai.add(m);

  // Verify basic operations work
  chai.eval(R"(
    auto vec = FooVector();
    var result = vec.size();
    result
  )");

  return 0;
}

